import React, { useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Loader2 } from 'lucide-react';
import toast from 'react-hot-toast';

interface TaxonomyFormProps {
  type: 'theme' | 'tag';
  onSuccess: () => void;
}

export const AdminTaxonomyForm = ({ type, onSuccess }: TaxonomyFormProps) => {
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    id: '',
    name: ''
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!formData.id.trim() || !formData.name.trim()) {
      return toast.error("Both ID and Name are required");
    }

    // Mapping keys to match your Theme and Tag models specifically
    const payload = type === 'theme' 
      ? { Theme_ID: formData.id, Theme_Name: formData.name, type } 
      : { Tag_ID: formData.id, Tag_Name: formData.name, type };

    setLoading(true);
    try {
      // Using the unified function now present in your AdminService
      await AdminService.upsertTaxonomy(payload);
      
      toast.success(`${type === 'theme' ? 'Theme' : 'Tag'} added to archive`);
      setFormData({ id: '', name: '' });
      onSuccess(); // Triggers the list refresh in AdminTaxonomy.tsx
    } catch (err: any) {
      const msg = err.response?.data?.error || "Save failed";
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-[#0f0f0f] p-6 rounded-3xl border border-white/5 space-y-4 shadow-xl">
      <div className="flex items-center gap-2 mb-1">
        <div className="w-1.5 h-1.5 rounded-full bg-primary" />
        <h2 className="text-white font-black uppercase text-[9px] tracking-widest italic">
          Register {type}
        </h2>
      </div>

      <form onSubmit={handleSubmit} className="space-y-3">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div className="space-y-1">
            <input 
              value={formData.id} 
              onChange={e => setFormData({...formData, id: e.target.value})} 
              placeholder={type === 'theme' ? "THEME001" : "TAG001"}
              className="w-full bg-white/5 border border-white/10 p-3 rounded-xl text-[10px] text-white outline-none focus:border-primary font-bold transition-all"
            />
          </div>
          <div className="space-y-1">
            <input 
              value={formData.name} 
              onChange={e => setFormData({...formData, name: e.target.value})} 
              placeholder="Display Name"
              className="w-full bg-white/5 border border-white/10 p-3 rounded-xl text-[10px] text-white outline-none focus:border-primary font-bold transition-all"
            />
          </div>
        </div>

        <button 
          type="submit" 
          disabled={loading}
          className="w-full bg-primary text-black py-3 rounded-xl font-black uppercase text-[9px] tracking-widest hover:bg-white transition-all flex items-center justify-center gap-2 disabled:opacity-50"
        >
          {loading ? (
            <Loader2 size={14} className="animate-spin" />
          ) : (
            <>
              <Plus size={14} /> Commit to Archive
            </>
          )}
        </button>
      </form>
    </div>
  );
};
